+		}
+		for _, agent := range agentsBySession[sess.Name] {
+			snapshotAgent := snapshotAgentFromRuntime(sess.Name, agent, paneLabels)
+			item.Agents = append(item.Agents, snapshotAgent)
+		}
+		output = append(output, item)
+	}
+
+	return output, nil
+}
